import { Cpu, Zap, Wifi } from 'lucide-react';
import { motion } from 'framer-motion';

interface QvacBadgeProps {
  model?: string;
  status?: 'idle' | 'loading' | 'running' | 'done';
  showGpu?: boolean;
  compact?: boolean;
}

export default function QvacBadge({ 
  model = 'LLAMA_3_2_1B_INST_Q4_0',
  status = 'idle',
  showGpu = false,
  compact = false
}: QvacBadgeProps) {
  const isActive = status === 'running' || status === 'loading';

  if (compact) {
    return (
      <span className="inline-flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-primary/10 border border-primary/20 text-primary text-[10px] font-bold tracking-wide">
        <span className="w-1.5 h-1.5 rounded-full bg-primary" />
        QVAC
      </span>
    );
  }

  return (
    <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-lg border text-xs font-mono ${
      isActive 
        ? 'bg-primary/10 border-primary/30 text-primary' 
        : 'bg-muted/50 border-border text-muted-foreground'
    }`}>
      <motion.div
        animate={isActive ? { rotate: 360 } : { rotate: 0 }}
        transition={isActive ? { duration: 2, repeat: Infinity, ease: 'linear' } : {}}
      >
        <Cpu className="w-3 h-3" />
      </motion.div>
      <span className="font-semibold">@qvac/sdk</span>
      <span className="text-muted-foreground opacity-70">·</span>
      <span className="truncate max-w-[180px]" title={model}>{model}</span>
      {showGpu && (
        <>
          <span className="text-muted-foreground opacity-70">·</span>
          <span className="text-amber-600 dark:text-amber-400 flex items-center gap-0.5">
            <Zap className="w-2.5 h-2.5" />Vulkan
          </span>
        </>
      )}
      <span className="ml-1 flex items-center gap-0.5 text-destructive/60">
        <Wifi className="w-2.5 h-2.5" />
        <span>offline</span>
      </span>
    </div>
  );
}

import clsx from 'clsx';
import { ShieldCheck, ShieldAlert, AlertTriangle, Loader2 } from 'lucide-react';

type RiskLevel = 'green' | 'amber' | 'red' | 'processing';

interface RiskBadgeProps {
  level: RiskLevel;
  text?: string;
  size?: 'sm' | 'md' | 'lg';
}

const config = {
  green: {
    label: 'Safe',
    icon: ShieldCheck,
    classes: 'bg-emerald-50 text-emerald-700 border-emerald-200',
    dot: 'bg-emerald-500',
  },
  amber: {
    label: 'Caution',
    icon: AlertTriangle,
    classes: 'bg-amber-50 text-amber-700 border-amber-200',
    dot: 'bg-amber-500',
  },
  red: {
    label: 'Danger',
    icon: ShieldAlert,
    classes: 'bg-red-50 text-red-700 border-red-200',
    dot: 'bg-red-500',
  },
  processing: {
    label: 'Analyzing',
    icon: Loader2,
    classes: 'bg-primary/5 text-primary border-primary/20',
    dot: 'bg-primary animate-pulse',
  },
};

export default function RiskBadge({ level, text, size = 'md' }: RiskBadgeProps) {
  const c = config[level];
  const Icon = c.icon;

  return (
    <span
      className={clsx(
        'inline-flex items-center gap-1.5 rounded-full border font-semibold',
        c.classes,
        size === 'sm' && 'px-2 py-0.5 text-[11px]',
        size === 'md' && 'px-2.5 py-1 text-xs',
        size === 'lg' && 'px-4 py-2 text-sm',
      )}
    >
      {level === 'processing' ? (
        <Icon className={clsx('animate-spin', size === 'lg' ? 'w-4 h-4' : 'w-3 h-3')} />
      ) : (
        <span className={clsx('rounded-full shrink-0', c.dot, size === 'lg' ? 'w-2.5 h-2.5' : 'w-2 h-2')} />
      )}
      {text ?? c.label}
    </span>
  );
}

