@import url('https://fonts.googleapis.com/css2?family=Cabinet+Grotesk:wght@400;500;700;800;900&family=Plus+Jakarta+Sans:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    --background: 40 25% 97%;
    --foreground: 220 45% 8%;

    --card: 0 0% 100%;
    --card-foreground: 220 45% 8%;

    --popover: 0 0% 100%;
    --popover-foreground: 220 45% 8%;

    --primary: 160 70% 14%;
    --primary-foreground: 40 25% 97%;

    --secondary: 35 45% 62%;
    --secondary-foreground: 220 45% 8%;

    --muted: 40 15% 93%;
    --muted-foreground: 220 12% 46%;

    --accent: 160 40% 92%;
    --accent-foreground: 160 70% 14%;

    --destructive: 0 80% 55%;
    --destructive-foreground: 0 0% 100%;

    --border: 220 13% 88%;
    --input: 220 13% 88%;
    --ring: 160 70% 14%;

    --radius: 0.5rem;

    --risk-green: 152 64% 28%;
    --risk-amber: 38 90% 48%;
    --risk-red: 0 78% 52%;

    --qvac-cyan: 188 85% 40%;
  }

  * {
    border-color: hsl(var(--border));
    box-sizing: border-box;
  }

  html {
    scroll-behavior: smooth;
  }

  body {
    background-color: hsl(var(--background));
    color: hsl(var(--foreground));
    font-family: 'Plus Jakarta Sans', sans-serif;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  h1, h2, h3, h4, h5, h6 {
    font-family: 'Cabinet Grotesk', sans-serif;
  }
}

@layer utilities {
  .font-mono-code {
    font-family: 'JetBrains Mono', monospace;
  }

  .hero-gradient {
    background: linear-gradient(135deg, hsl(160 70% 14%) 0%, hsl(160 55% 20%) 50%, hsl(220 45% 12%) 100%);
  }

  .card-hover {
    transition: all 0.2s cubic-bezier(0.19, 1, 0.22, 1);
  }
  .card-hover:hover {
    transform: translateY(-2px);
    box-shadow: 0 12px 40px -8px rgba(11, 59, 45, 0.15);
  }

  .text-gradient-gold {
    background: linear-gradient(135deg, hsl(var(--secondary)) 0%, hsl(38 75% 55%) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  .noise-texture {
    position: relative;
  }
  .noise-texture::before {
    content: '';
    position: absolute;
    inset: 0;
    opacity: 0.025;
    pointer-events: none;
    z-index: 0;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  }
}

/** @type {import('tailwindcss').Config} */
export default {
  content: [
    "./index.html",
    "./src/**/*.{js,ts,jsx,tsx}",
  ],
  theme: {
    extend: {
      colors: {
        border: "hsl(var(--border))",
        input: "hsl(var(--input))",
        ring: "hsl(var(--ring))",
        background: "hsl(var(--background))",
        foreground: "hsl(var(--foreground))",
        primary: {
          DEFAULT: "hsl(var(--primary))",
          foreground: "hsl(var(--primary-foreground))",
        },
        secondary: {
          DEFAULT: "hsl(var(--secondary))",
          foreground: "hsl(var(--secondary-foreground))",
        },
        destructive: {
          DEFAULT: "hsl(var(--destructive))",
          foreground: "hsl(var(--destructive-foreground))",
        },
        muted: {
          DEFAULT: "hsl(var(--muted))",
          foreground: "hsl(var(--muted-foreground))",
        },
        accent: {
          DEFAULT: "hsl(var(--accent))",
          foreground: "hsl(var(--accent-foreground))",
        },
        card: {
          DEFAULT: "hsl(var(--card))",
          foreground: "hsl(var(--card-foreground))",
        },
        risk: {
          green: "hsl(var(--risk-green))",
          amber: "hsl(var(--risk-amber))",
          red: "hsl(var(--risk-red))",
        },
        qvac: {
          cyan: "hsl(var(--qvac-cyan))",
        },
        gold: {
          DEFAULT: "hsl(var(--secondary))",
          light: "hsl(38 75% 70%)",
          dark: "hsl(35 65% 35%)",
        },
      },
      fontFamily: {
        sans: ['"Plus Jakarta Sans"', 'sans-serif'],
        display: ['"Cabinet Grotesk"', 'sans-serif'],
        mono: ['"JetBrains Mono"', 'monospace'],
      },
      borderRadius: {
        lg: "var(--radius)",
        md: "calc(var(--radius) - 2px)",
        sm: "calc(var(--radius) - 4px)",
      },
      boxShadow: {
        'glow-primary': '0 0 40px -10px hsl(160 70% 14% / 0.3)',
        'glow-gold': '0 0 30px -8px hsl(35 45% 62% / 0.4)',
      },
      keyframes: {
        shimmer: {
          '0%': { backgroundPosition: '-200% 0' },
          '100%': { backgroundPosition: '200% 0' },
        },
        fadeUp: {
          '0%': { opacity: '0', transform: 'translateY(16px)' },
          '100%': { opacity: '1', transform: 'translateY(0)' },
        },
        pulse2: {
          '0%, 100%': { opacity: '1' },
          '50%': { opacity: '0.5' },
        }
      },
      animation: {
        shimmer: 'shimmer 2.5s linear infinite',
        'fade-up': 'fadeUp 0.5s ease forwards',
        'pulse2': 'pulse2 2s ease-in-out infinite',
      },
    },
  },
  plugins: [],
}

import { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, Wifi } from 'lucide-react';
import { VakeelLogo, VakeelWordmark } from './Logo';

const navLinks = [
  { to: '/features', label: 'Features' },
  { to: '/how-it-works', label: 'How it Works' },
  { to: '/vault', label: 'My Vault' },
];

export default function Navbar() {
  const [open, setOpen] = useState(false);
  const location = useLocation();

  return (
    <header className="sticky top-0 z-50 w-full border-b border-border/50 bg-background/85 backdrop-blur-xl">
      <div className="container mx-auto px-4 h-16 flex items-center justify-between max-w-7xl">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-2.5 group shrink-0">
          <VakeelLogo className="w-8 h-9 transition-transform group-hover:scale-105" />
          <VakeelWordmark className="text-xl text-foreground" />
        </Link>

        {/* Desktop nav */}
        <nav className="hidden md:flex items-center gap-1">
          {navLinks.map((link) => (
            <Link
              key={link.to}
              to={link.to}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                location.pathname === link.to
                  ? 'bg-primary/10 text-primary'
                  : 'text-muted-foreground hover:text-foreground hover:bg-muted'
              }`}
            >
              {link.label}
            </Link>
          ))}
        </nav>

        {/* Right side */}
        <div className="hidden md:flex items-center gap-3">
          {/* Offline indicator */}
          <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-muted text-muted-foreground text-xs font-mono border border-border">
            <Wifi className="w-3 h-3 line-through opacity-50" />
            <span>100% offline</span>
          </span>
          <Link
            to="/analyze/tax-loan"
            className="bg-primary text-primary-foreground px-4 py-2 rounded-lg text-sm font-bold hover:bg-primary/90 transition-all shadow-sm hover:shadow-glow-primary"
          >
            Try Demo
          </Link>
        </div>

        {/* Mobile hamburger */}
        <button
          className="md:hidden p-2 rounded-md text-muted-foreground hover:text-foreground hover:bg-muted"
          onClick={() => setOpen(!open)}
          aria-label="Toggle menu"
        >
          {open ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
        </button>
      </div>

      {/* Mobile menu */}
      {open && (
        <div className="md:hidden border-t border-border bg-background">
          <nav className="container mx-auto px-4 py-4 flex flex-col gap-1">
            {navLinks.map((link) => (
              <Link
                key={link.to}
                to={link.to}
                onClick={() => setOpen(false)}
                className="px-4 py-2.5 rounded-md text-sm font-medium text-foreground hover:bg-muted transition-colors"
              >
                {link.label}
              </Link>
            ))}
            <Link
              to="/analyze/tax-loan"
              onClick={() => setOpen(false)}
              className="mt-2 bg-primary text-primary-foreground px-4 py-2.5 rounded-lg text-sm font-bold text-center"
            >
              Try Demo
            </Link>
          </nav>
        </div>
      )}
    </header>
  );
}

