    type: 'Title Deed',
    date: 'Sep 28, 2023',
    risk: 'red' as const,
    size: '5.1 MB',
    category: 'Land & Property',
    analyzeLink: '/analyze/land-title',
    deadline: 'Proposed signing Jul 1, 2024',
  },
  {
    id: 3,
    name: 'US_Tech_OfferLetter_Remote.pdf',
    type: 'Employment Contract',
